   672→// Get practice statistics
   673→router.get('/practice/stats', authMiddleware, async (req, res) => {
   674→  try {
   675→    const stats = await pool.query(
   676→      `SELECT
   677→        COUNT(*) as total_questions,
   678→        AVG(score) as average_score,
   679→        MAX(created_at) as last_practice
   680→       FROM practice_sessions
   681→       WHERE user_id = $1`,
   682→      [req.user.id]
   683→    );
   684→
   685→    // Calculate improvement (compare first half vs second half of sessions)
   686→    const improvement = await pool.query(
   687→      `WITH ordered_sessions AS (
   688→        SELECT score, ROW_NUMBER() OVER (ORDER BY created_at) as rn,
   689→               COUNT(*) OVER () as total
   690→        FROM practice_sessions
   691→        WHERE user_id = $1
   692→      )
   693→      SELECT
   694→        AVG(CASE WHEN rn <= total/2 THEN score END) as first_half_avg,
   695→        AVG(CASE WHEN rn > total/2 THEN score END) as second_half_avg
   696→      FROM ordered_sessions`,
   697→      [req.user.id]
   698→    );
   699→
   700→    let improvementPercent = null;
   701→    if (improvement.rows[0].first_half_avg && improvement.rows[0].second_half_avg) {
   702→      const firstHalf = parseFloat(improvement.rows[0].first_half_avg);
   703→      const secondHalf = parseFloat(improvement.rows[0].second_half_avg);
   704→      improvementPercent = ((secondHalf - firstHalf) / firstHalf) * 100;
   705→    }
   706→
   707→    // Calculate day streak
   708→    const streakResult = await pool.query(
   709→      `WITH RECURSIVE date_series AS (
   710→        SELECT CURRENT_DATE::date as check_date, 0 as days_back
   711→        UNION ALL
   712→        SELECT (check_date - INTERVAL '1 day')::date, days_back + 1
   713→        FROM date_series
   714→        WHERE days_back < 30
   715→      )
   716→      SELECT COUNT(*) as streak
   717→      FROM date_series d
   718→      WHERE EXISTS (
   719→        SELECT 1 FROM practice_sessions
   720→        WHERE user_id = $1 AND DATE(created_at) = d.check_date
   721→      )
   722→      AND d.check_date <= CURRENT_DATE
   723→      AND NOT EXISTS (
   724→        SELECT 1 FROM date_series d2
   725→        WHERE d2.check_date > d.check_date
   726→        AND d2.check_date <= CURRENT_DATE
   727→        AND NOT EXISTS (
   728→          SELECT 1 FROM practice_sessions
   729→          WHERE user_id = $1 AND DATE(created_at) = d2.check_date
   730→        )
   731→      )`,
   732→      [req.user.id]
   733→    );
   734→
   735→    res.json({
   736→      success: true,
   737→      stats: {
   738→        total_questions: parseInt(stats.rows[0].total_questions) || 0,
   739→        average_score: parseFloat(stats.rows[0].average_score) || null,
   740→        improvement: improvementPercent,
   741→        day_streak: parseInt(streakResult.rows[0].streak) || 0,
   742→        last_practice: stats.rows[0].last_practice
   743→      }
